import http from '../http'
//




// 技术指标详列表
export function testReportQualifcationtList(query: any) {
    return http.get('/jkyErp/testReportQualifcation/list', query)
}

// 根据ID查询技术指标详情信息
export function gettestReportQualifcation(id: any) {
    return http.get('/jkyErp/testReportQualifcation/' + id)
}
// 新增技术指标详
export function addtestReportQualifcationt(data: any) {
    return http.post('/jkyErp/testReportQualifcation/add', data)
}

// 修改技术指标详
export function editestReportQualifcation(data: any) {
    return http.post('/jkyErp/testReportQualifcation/edit', data)
}

// 删除技术指标详
export function deltestReportQualifcation(teamId: number) {
    return http.post('/jkyErp/testReportQualifcation/del',teamId)
}







