<template>
  <a-card>
    <div :class="advanced ? 'search' : null">
      <a-form layout="horizontal">
        <div :class="advanced ? null : 'fold'">
          <a-row>
            <a-col :md="8" :sm="24">
              <a-form-item
                label="指标内容"
                :labelCol="{ span: 5 }"
                :wrapperCol="{ span: 18, offset: 1 }"
              >
                <a-input
                  placeholder="请输入指标内容"
                  v-model:value="queryParams.specsContent"
                />
              </a-form-item>
            </a-col>
          </a-row>
        </div>
        <span style="float: right; margin-top: 3px">
          <a-button type="primary" @click="handleSearch">查询</a-button>
          <a-button style="margin-left: 8px" @click="Reset">重置</a-button>
          <a @click="toggleAdvanced" style="margin-left: 8px">
            {{ advanced ? "收起" : "展开" }}
          </a>
        </span>
      </a-form>
    </div>
    <div>
      <a-space class="operator">
        <a-button @click="handleAdd" type="primary">新建</a-button>
        <a-button
          @click="handleUpdate"
          type="primary"
          :disabled="selectedRowKeys.length == 1 ? false : true"
          >编辑</a-button
        >
        <a-button
          @click="handleDel"
          type="primary"
          :disabled="selectedRowKeys.length > 0 ? false : true"
          danger
          >删除
        </a-button>
      </a-space>
      <a-table
        rowKey="id"
        :pagination="false"
        :columns="columns"
        :data-source="dataSource"
        :row-selection="{
          selectedRowKeys: selectedRowKeys,
          onChange: onSelectChange,
        }"
      >
      </a-table>
      <a-pagination
        v-show="total > 0"
        show-size-changer
        :show-total="(total) => `共 ${total} 条`"
        v-model:current="queryParams.current"
        v-model:pageSize="queryParams.size"
        :total="total"
        show-less-items
        @showSizeChange="onShowSizeChange"
        @change="onPageChange"
      />
    </div>
  </a-card>

  <a-modal
    :visible="open"
    :title="title"
    width="650px"
    @ok="handleOk"
    @cancel="handleCancel"
  >
    <a-form :model="form">
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="产品" :rules="[{ required: true }]">
            <a-select
              :allowClear="true"
              @select="select"
              showSearch
              optionFilterProp="lable"
              v-model:value="province"
              placeholder="请选择产品"
            >
              <a-select-option
                v-for="item in productList"
                :key="item.productId"
                :lable="item.productName"
                :value="item.productId"
              >
                {{ item.productName }}
              </a-select-option>
            </a-select>
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="检测项" :rules="[{ required: true }]">
            <a-tree-select
              v-model:value="form.checkItemId"
              showSearch
              treeNodeFilterProp="checkItemName"
              style="width: 180px"
              placeholder="请选择检测项"
              :dropdown-style="{ maxHeight: '400px', overflow: 'auto' }"
              notFoundContent="未选择产品或产品下没有检测项"
              allow-clear
              :tree-data="productItemList"
              :replaceFields="{
                children: 'children',
                label: 'checkItemName',
                key: 'checkItemId',
                value: 'checkItemId',
              }"
            ></a-tree-select>
          </a-form-item>
        </a-col>
      </a-row>

      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="conditionKey">
            <a-input
              placeholder="请输入conditionKey"
              v-model:value="form.conditionKey"
            />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="前置条件值">
            <a-input
              placeholder="请输入前置条件值"
              v-model:value="form.conditionValue"
            />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="24">
          <a-form-item label="指标内容">
            <a-textarea
              rows="4"
              placeholder="请输入指标内容"
              v-model:value="form.specsContent"
              show-count
              :maxlength="100"
            />
          </a-form-item>
        </a-col>
      </a-row>
    </a-form>
  </a-modal>
</template>

<script>
const columns = [
  {
    title: "编号",
    dataIndex: "id",
  },
  {
    title: "检测项",
    dataIndex: "checkItemName",
  },
  {
    title: "指标内容",
    dataIndex: "specsContent",
  },
  {
    title: "conditionKey",
    dataIndex: "conditionKey",
  },
  {
    title: "前置条件值",
    dataIndex: "conditionValue",
  },
];
import {
  testReportQualifcationtList,
  addtestReportQualifcationt,
  gettestReportQualifcation,
  deltestReportQualifcation,
  editestReportQualifcation,
} from "@/server/http/api/testReportQualifcation";

import { ProductListAll, itemList, getitem } from "@/server/http/api/Product";
import { message } from "ant-design-vue";
export default {
  name: "QueryList",
  components: {},
  data() {
    return {
      // 弹出层标题
      title: "",
      // 是否显示弹出层
      open: false,
      advanced: false,
      columns: columns,
      dataSource: [],
      selectedRows: [],
      selectedRowKeys: [],
      // 表单参数
      form: {},
      Pagination: {},
      total: 0,

      queryParams: {
        current: 1,
        size: 10,
        checkItemName: undefined,
      },
      // 选中数组
      ids: [],
      // 非单个禁用
      single: true,
      // 非多个禁用
      multiple: true,
      // 产品列表
      productList: [],
      // 产品检测项
      productItemList: [],
      //暂存产品ID
      province: null,
    };
  },
  authorize: {
    deleteRecord: "delete",
  },
  created() {
    this.getList();
  },
  mounted() {
    this.getProductList();
  },
  watch: {
    province(e) {
      if (e == null || e == "") {
        this.productItemList = [];
        return;
      }
      itemList({
        productId: e,
        status: "0",
      }).then((res) => {
        var data = res.data;
        this.productItemList = data.data;
      });
    },
  },
  methods: {
    select() {
      this.form.checkItemId = null;
    },
    onShowSizeChange(current, pageSize) {
      this.queryParams.current = current;
      this.queryParams.size = pageSize;
      this.getList();
    },
    onPageChange(pageNumber) {
      this.queryParams.current = pageNumber;
      this.getList();
    },
    //获取设备分类列表
    getList() {
      testReportQualifcationtList(this.queryParams).then((res) => {
        var data = res.data;
        this.dataSource = data.data.records;
        this.total = data.data.total;
      });
    },
    //获取产品列表
    getProductList() {
      ProductListAll().then((res) => {
        var data = res.data;
        this.productList = data.data;
      });
    },

    //查询数据
    handleSearch() {
      this.getList();
    },
    Reset() {
      this.queryParams = {
        current: 1,
        size: 10,
        name: undefined,
      };
      this.getList();
    },
    handleOk(e) {
      if (!this.form.checkItemId) {
        message.warning("缺少必填参数!");
        return;
      }
      this.submitForm();
    },
    handleCancel(e) {
      this.form = {};
      this.province = null;
      this.open = false;
    },
    deleteRecord(key) {
      this.dataSource = this.dataSource.filter((item) => item.key !== key);
      this.selectedRows = this.selectedRows.filter((item) => item.key !== key);
    },
    toggleAdvanced() {
      this.advanced = !this.advanced;
    },
    remove() {
      this.dataSource = this.dataSource.filter(
        (item) =>
          this.selectedRows.findIndex((row) => row.key === item.key) === -1
      );
      this.selectedRows = [];
    },
    onSelectChange(selection) {
      this.ids = selection.map((item) => item.id);
      this.single = selection.length !== 1;
      this.multiple = !selection.length;
      this.selectedRowKeys = selection;
    },
    /** 新增按钮操作 */
    handleAdd() {
      //this.reset();
      this.open = true;
      this.title = "添加标准";
    },
    /** 修改按钮操作 */
    handleUpdate(row) {
      this.loading = true;
      gettestReportQualifcation(this.selectedRowKeys[0]).then((response) => {
        this.loading = false;
        this.form = response.data.data;
        this.open = true;
        this.title = "修改标准";
        getitem(this.form.checkItemId).then((response) => {
          this.province = response.data.data.testProductItem.productId;
        });
      });
    },
    /** 提交按钮 */
    submitForm() {
      this.buttonLoading = true;
      if (this.form.id != null) {
        editestReportQualifcation(this.form)
          .then((response) => {
            this.open = false;
            this.form = {};
            this.getList();
            this.province = null;
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      } else {
        addtestReportQualifcationt(this.form)
          .then((response) => {
            this.open = false;
            this.form = {};
            this.getList();
            this.province = null;
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      }
    },
    handleDel() {
      deltestReportQualifcation(this.selectedRowKeys)
        .then((response) => {
          this.selectedRowKeys = [];
          this.getList();
        })
        .finally(() => {
          this.buttonLoading = false;
        });
    },
  },
};
</script>

<style lang="less" scoped>
.search {
  margin-bottom: 54px;
}
.fold {
  width: calc(100% - 216px);
  display: inline-block;
}
.operator {
  margin-bottom: 18px;
}
@media screen and (max-width: 900px) {
  .fold {
    width: 100%;
  }
}
</style>
